import{_ as a,c as e,o as s,ag as n}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"核心概念","description":"","frontmatter":{},"headers":[],"relativePath":"memx/concepts.md","filePath":"memx/concepts.md","lastUpdated":1772252630000}'),o={name:"memx/concepts.md"};function d(l,t,i,p,c,r){return s(),e("div",null,[...t[0]||(t[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /memx\\concepts.md for this page in Markdown format</div><h1 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h1><p>MemX 的 ACE（Adaptive Context Engine）引擎由四大核心模块组成，每个模块独立运作、协同配合，实现知识的完整生命周期管理。</p><h2 id="reflector-—-知识蒸馏引擎" tabindex="-1">Reflector — 知识蒸馏引擎 <a class="header-anchor" href="#reflector-—-知识蒸馏引擎" aria-label="Permalink to &quot;Reflector — 知识蒸馏引擎&quot;">​</a></h2><p>Reflector 是 MemX 最核心的创新：<strong>极低成本</strong>的智能知识提取。</p><p>传统 AI 记忆系统依赖 LLM 调用来从对话中提取知识点，每次消耗 2-5K tokens。Reflector 支持三种运行模式，默认使用 <strong>hybrid</strong> 混合模式，通过规则预筛选大幅减少 LLM 调用，仅对有价值的候选项调用 LLM 精炼，相比全量 LLM 方案减少 90%+ 的调用开销。</p><h3 id="三种运行模式" tabindex="-1">三种运行模式 <a class="header-anchor" href="#三种运行模式" aria-label="Permalink to &quot;三种运行模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>说明</th><th>LLM 开销</th></tr></thead><tbody><tr><td><code>rules</code></td><td>纯规则引擎，完全基于模式匹配</td><td>零 LLM 调用</td></tr><tr><td><code>hybrid</code>（默认）</td><td>规则预筛选 + LLM 精炼，取平均分数</td><td>仅对候选项调用，减少 90%+</td></tr><tr><td><code>llm</code></td><td>完全依赖 LLM 提取知识</td><td>每次 2-5K tokens</td></tr></tbody></table><p><strong>hybrid 工作流程</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原始对话 → PatternDetector (规则检测) → 候选知识项</span></span>
<span class="line"><span>                                           ↓</span></span>
<span class="line"><span>                              LLM 评估 + 蒸馏 (仅对候选项)</span></span>
<span class="line"><span>                                           ↓</span></span>
<span class="line"><span>                              取规则分数与 LLM 分数的平均值</span></span>
<span class="line"><span>                                           ↓</span></span>
<span class="line"><span>                        KnowledgeScorer → PrivacySanitizer → BulletDistiller</span></span>
<span class="line"><span>                            评分分类          隐私脱敏           压缩精炼</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>当 LLM 不可用时（API 故障、网络问题），hybrid 模式自动降级到 rules 模式，确保服务不中断。</p></div><h3 id="五种检测规则" tabindex="-1">五种检测规则 <a class="header-anchor" href="#五种检测规则" aria-label="Permalink to &quot;五种检测规则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>规则</th><th>检测逻辑</th><th>置信度</th><th>典型场景</th></tr></thead><tbody><tr><td>ErrorFixRule</td><td>识别「报错 → 解决方案」结构</td><td>0.8</td><td>&quot;TypeError: ... → 原来要加类型断言&quot;</td></tr><tr><td>RetrySuccessRule</td><td>检测多次尝试后的成功路径</td><td>0.7</td><td>&quot;试了 A、B 都不行，最后 C 方案解决&quot;</td></tr><tr><td>ConfigChangeRule</td><td>匹配配置/环境变量修改</td><td>0.6</td><td>&quot;把 MAX_POOL_SIZE 从 10 改到 50&quot;</td></tr><tr><td>NewToolRule</td><td>识别首次使用的工具/库</td><td>0.65</td><td>&quot;第一次用 pnpm，比 npm 快多了&quot;</td></tr><tr><td>RepetitiveOpRule</td><td>统计重复操作（≥3 次触发）</td><td>0.5+</td><td>&quot;每次部署都要手动清理缓存&quot;</td></tr></tbody></table><h3 id="知识分类体系" tabindex="-1">知识分类体系 <a class="header-anchor" href="#知识分类体系" aria-label="Permalink to &quot;知识分类体系&quot;">​</a></h3><p>每条被提取的知识自动归入 <strong>Section</strong>（主题）和 <strong>KnowledgeType</strong>（类型）两个维度：</p><p><strong>8 种 Section</strong>: <code>COMMANDS</code> · <code>DEBUGGING</code> · <code>ARCHITECTURE</code> · <code>WORKFLOW</code> · <code>TOOLS</code> · <code>PATTERNS</code> · <code>PREFERENCES</code> · <code>GENERAL</code></p><p><strong>5 种 KnowledgeType</strong>: <code>METHOD</code>（方法论） · <code>TRICK</code>（技巧） · <code>PITFALL</code>（踩坑） · <code>PREFERENCE</code>（偏好） · <code>KNOWLEDGE</code>（事实）</p><h3 id="instructivity-score" tabindex="-1">Instructivity Score <a class="header-anchor" href="#instructivity-score" aria-label="Permalink to &quot;Instructivity Score&quot;">​</a></h3><p>每条知识获得 0-100 的<strong>教学价值评分</strong>。分数由以下因素综合计算：</p><ul><li>模式匹配的置信度</li><li>知识的具体性和可操作性</li><li>是否包含明确的因果关系</li></ul><p>低于 <code>min_score</code>（默认 30）的候选项被丢弃，避免噪音污染知识库。</p><h2 id="curator-—-语义去重引擎" tabindex="-1">Curator — 语义去重引擎 <a class="header-anchor" href="#curator-—-语义去重引擎" aria-label="Permalink to &quot;Curator — 语义去重引擎&quot;">​</a></h2><p>随着知识积累，不可避免会出现重复和矛盾。Curator 在每次写入时自动处理：</p><h3 id="三级去重策略" tabindex="-1">三级去重策略 <a class="header-anchor" href="#三级去重策略" aria-label="Permalink to &quot;三级去重策略&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>新知识写入</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>计算与现有知识的余弦相似度</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── ≥ 0.8  → 自动合并（keep_best 或 merge_content）</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 0.5~0.8 → 标记潜在冲突，等待确认</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── &lt; 0.5  → 视为独立知识，正常写入</span></span></code></pre></div><p><strong>合并策略</strong>:</p><ul><li><code>keep_best</code>（默认）: 保留 instructivity_score 更高的版本</li><li><code>merge_content</code>: 合并两条知识的内容，生成更完整的版本</li></ul><h3 id="冲突检测" tabindex="-1">冲突检测 <a class="header-anchor" href="#冲突检测" aria-label="Permalink to &quot;冲突检测&quot;">​</a></h3><p>主动扫描知识库中的矛盾记忆，例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>冲突: &quot;Redis 连接池设置 10 即可&quot; vs &quot;Redis 连接池至少 50 才稳定&quot;</span></span>
<span class="line"><span>原因: 相似度 0.72，但结论相反</span></span>
<span class="line"><span>建议: 确认当前最佳实践，删除过时版本</span></span></code></pre></div><p>通过 CLI 可以随时检测：<code>memx conflicts</code></p><h2 id="decay-—-时间衰减引擎" tabindex="-1">Decay — 时间衰减引擎 <a class="header-anchor" href="#decay-—-时间衰减引擎" aria-label="Permalink to &quot;Decay — 时间衰减引擎&quot;">​</a></h2><p>模拟人类记忆的自然遗忘曲线，确保知识库始终保持&quot;新鲜&quot;。</p><h3 id="衰减公式" tabindex="-1">衰减公式 <a class="header-anchor" href="#衰减公式" aria-label="Permalink to &quot;衰减公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>base_weight = 2^(-age_days / half_life)</span></span>
<span class="line"><span>boosted     = base_weight × (1 + boost_factor × recall_count)</span></span>
<span class="line"><span>final       = clamp(boosted, 0.0, 1.0)</span></span></code></pre></div><p><strong>核心参数</strong>:</p><table tabindex="0"><thead><tr><th>参数</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>half_life</code></td><td>30 天</td><td>权重衰减到 50% 所需的天数</td></tr><tr><td><code>boost_factor</code></td><td>0.1</td><td>每次召回的权重加成系数</td></tr></tbody></table><h3 id="三层保护机制" tabindex="-1">三层保护机制 <a class="header-anchor" href="#三层保护机制" aria-label="Permalink to &quot;三层保护机制&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>recall_count ≥ 15  →  永久记忆（weight 固定为 1.0）</span></span>
<span class="line"><span>age ≤ 7 天          →  保护期（weight 固定为 1.0）</span></span>
<span class="line"><span>weight &lt; 0.02       →  归档候选（可清理）</span></span></code></pre></div><p><strong>直觉理解</strong>: 就像人的记忆一样——</p><ul><li>刚学到的东西（7 天内）记得很清楚</li><li>经常回忆的知识越来越牢固</li><li>被反复使用 15 次以上的知识成为&quot;肌肉记忆&quot;</li><li>长时间不用的知识逐渐模糊，最终遗忘</li></ul><h3 id="检索时的衰减影响" tabindex="-1">检索时的衰减影响 <a class="header-anchor" href="#检索时的衰减影响" aria-label="Permalink to &quot;检索时的衰减影响&quot;">​</a></h3><p>衰减权重直接参与检索排序的最终评分：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Final Score = Blended Search Score × DecayWeight × RecencyBoost × ScopeBoost</span></span></code></pre></div><ul><li><code>RecencyBoost</code>: 7 天内创建的知识获得 1.2x 加成</li><li><code>ScopeBoost</code>: 匹配当前作用域的知识获得 1.3x 加成</li></ul><h2 id="generator-—-混合检索引擎" tabindex="-1">Generator — 混合检索引擎 <a class="header-anchor" href="#generator-—-混合检索引擎" aria-label="Permalink to &quot;Generator — 混合检索引擎&quot;">​</a></h2><p>突破纯向量搜索的局限，四层搜索覆盖从精确匹配到语义理解的完整频谱。</p><h3 id="四层搜索架构" tabindex="-1">四层搜索架构 <a class="header-anchor" href="#四层搜索架构" aria-label="Permalink to &quot;四层搜索架构&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>引擎</th><th>匹配方式</th><th>优势场景</th></tr></thead><tbody><tr><td>L1</td><td>ExactMatcher</td><td>精确词匹配</td><td>&quot;pytest -v&quot;、API 名称</td></tr><tr><td>L2</td><td>FuzzyMatcher</td><td>模糊 Token 匹配</td><td>拼写变体、形态变化</td></tr><tr><td>L3</td><td>MetadataMatcher</td><td>tools / entities / tags 的 Jaccard 相似度</td><td>&quot;关于 Redis 的知识&quot;</td></tr><tr><td>L4</td><td>VectorSearcher</td><td>向量嵌入语义搜索</td><td>&quot;如何提升测试性能&quot;</td></tr></tbody></table><h3 id="分数融合公式" tabindex="-1">分数融合公式 <a class="header-anchor" href="#分数融合公式" aria-label="Permalink to &quot;分数融合公式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NormKeyword = (L1 + L2 + L3) / 35.0        # 归一化到 [0, 1]</span></span>
<span class="line"><span>Blended     = NormKeyword × 0.6 + Semantic × 0.4</span></span>
<span class="line"><span>Final       = Blended × DecayWeight × RecencyBoost × ScopeBoost</span></span></code></pre></div><p>关键词搜索权重（0.6）高于语义搜索（0.4），确保精确匹配的结果优先展示。</p><h3 id="优雅降级" tabindex="-1">优雅降级 <a class="header-anchor" href="#优雅降级" aria-label="Permalink to &quot;优雅降级&quot;">​</a></h3><p>当 L4 向量搜索不可用时（如嵌入模型加载失败），自动降级为纯关键词模式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>keyword_weight = 1.0, semantic_weight = 0.0</span></span></code></pre></div><p>系统在任何单一搜索层故障时都不会中断服务。</p><h2 id="token-预算管理" tabindex="-1">Token 预算管理 <a class="header-anchor" href="#token-预算管理" aria-label="Permalink to &quot;Token 预算管理&quot;">​</a></h2><p>检索结果受双重约束：</p><ul><li><code>max_results</code>: 最大返回条数（默认 5）</li><li><code>token_budget</code>: 最大 Token 预算（默认 2000）</li></ul><h3 id="cjk-感知" tabindex="-1">CJK 感知 <a class="header-anchor" href="#cjk-感知" aria-label="Permalink to &quot;CJK 感知&quot;">​</a></h3><p>MemX 对中日韩文字使用更精确的 Token 估算：</p><table tabindex="0"><thead><tr><th>字符类型</th><th>估算比例</th></tr></thead><tbody><tr><td>CJK 字符</td><td>1.5 字符 / token</td></tr><tr><td>拉丁字符</td><td>4.0 字符 / token</td></tr></tbody></table><p>这确保中文内容不会因为错误的 Token 估算而被过度裁剪。</p><h2 id="层级作用域" tabindex="-1">层级作用域 <a class="header-anchor" href="#层级作用域" aria-label="Permalink to &quot;层级作用域&quot;">​</a></h2><p>知识按层级组织，实现精准的访问控制：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>global                    ← 所有项目可见</span></span>
<span class="line"><span>├── project:my-backend    ← 仅该项目可见</span></span>
<span class="line"><span>│   └── workspace:feat-auth  ← 仅该工作区可见</span></span>
<span class="line"><span>└── project:my-frontend</span></span></code></pre></div><ul><li>检索时，匹配当前 scope 的知识获得 1.3x 评分加成</li><li>上层 scope 的知识对下层可见（global 对所有项目可见）</li><li>下层 scope 的知识对上层不可见</li></ul>`,67)])])}const b=a(o,[["render",d]]);export{u as __pageData,b as default};
